const ID_MAP = {
    'CS0001': 'USB0001',
    'CS0002': 'CAB0001',
    'CS0003': 'CAB0002',
    'CS0004': 'CAB0003',
    'CS0005': 'CAB0004',
    'CS0006': 'CAB0005',
    'CS0007': 'CAB0006',
    'CS0008': 'CAB0007',
    'CS0009': 'CAB0008',
    'CS0010': 'CAB0009',
    'CS0011': 'CAB0010'
};

function normalizeStationId(value) {
    const stationid = String(value || '').trim();
    return ID_MAP[stationid] || stationid;
}

const authUser = msg._authContext?.user || (msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload) ? JSON.parse(JSON.stringify(msg.payload)) : null);
const command = (msg.command && typeof msg.command === 'object') ? JSON.parse(JSON.stringify(msg.command)) : {};
const stationid = normalizeStationId(command.stationid || msg.stationid || '');
const moduleid = String(command.moduleid || command.moduleId || '').trim();

if (!stationid) {
    node.error('Update module command is missing stationid', msg);
    return null;
}

if (!moduleid) {
    node.error('Update module command is missing moduleid', msg);
    return null;
}

msg._updateModuleAuthUser = authUser;
msg._updateModuleCommand = command;
msg._updateModuleStationId = stationid;
msg._updateModuleId = moduleid;
msg.payload = {
    path: 'kiosks',
    query: [{ fieldPath: 'stationid', opStr: '==', value: stationid }]
};

return msg;

const ID_MAP = {
    'CS0001': 'USB0001',
    'CS0002': 'CAB0001',
    'CS0003': 'CAB0002',
    'CS0004': 'CAB0003',
    'CS0005': 'CAB0004',
    'CS0006': 'CAB0005',
    'CS0007': 'CAB0006',
    'CS0008': 'CAB0007',
    'CS0009': 'CAB0008',
    'CS0010': 'CAB0009',
    'CS0011': 'CAB0010'
};

function normalizeStationId(value) {
    const stationid = String(value || '').trim();
    return ID_MAP[stationid] || stationid;
}

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const stationid = normalizeStationId(msg._updateModuleStationId || '');
const matched = docs.find((doc) => normalizeStationId(doc?.stationid || '') === stationid) || null;

msg.kioskDoc = matched ? JSON.parse(JSON.stringify(matched)) : null;
msg.stationid = (matched && matched.stationid) || stationid;
msg.command = msg._updateModuleCommand || msg.command || {};
msg.payload = msg._updateModuleCommand || {};

return msg;

const V2_TYPES = new Set(['CT3', 'CT4', 'CT8', 'CT12', 'CK48']);
const ONLINE_WINDOW_MS = 10 * 60 * 1000;
const ID_MAP = {
    'CS0001': 'USB0001',
    'CS0002': 'CAB0001',
    'CS0003': 'CAB0002',
    'CS0004': 'CAB0003',
    'CS0005': 'CAB0004',
    'CS0006': 'CAB0005',
    'CS0007': 'CAB0006',
    'CS0008': 'CAB0007',
    'CS0009': 'CAB0008',
    'CS0010': 'CAB0009',
    'CS0011': 'CAB0010'
};

function parseTimestamp(value) {
    if (!value) return null;
    const parsed = new Date(value);
    return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function normalizeStationId(value) {
    const stationid = String(value || '').trim();
    return ID_MAP[stationid] || stationid;
}

function normalizeModuleId(value) {
    return String(value || '').trim();
}

function modulesMatch(left, right) {
    const a = normalizeModuleId(left);
    const b = normalizeModuleId(right);
    if (!a || !b) return false;
    if (a === b) return true;
    return a.replace(/^1000/, '') === b.replace(/^1000/, '');
}

function buildResponse(sessionValue, command, status, statusEn) {
    return {
        _session: sessionValue,
        payload: {
            action: 'update module',
            stationid: command.stationid,
            moduleid: command.moduleid,
            status,
            status_en: statusEn,
            requestId: command.requestId,
            timerequested: command.timerequested,
            timeresponded: Date.now()
        }
    };
}

function normalizeFirmwareTarget(value) {
    const target = String(value || '').trim().toLowerCase();
    if (target === '12b') return '12B';
    if (target === '12m') return '12M';
    if (target === 'mcu') return 'mcu';
    return '12B';
}

function firmwareSessionWrite(session) {
    if (!session || !session.requestId) return null;
    return {
        payload: {
            path: 'firmwareUpdateSessions/' + session.requestId,
            content: session
        }
    };
}

const authUser = msg._updateModuleAuthUser || msg._authContext?.user || null;
const command = (msg._updateModuleCommand && typeof msg._updateModuleCommand === 'object')
    ? msg._updateModuleCommand
    : (msg.command || {});
const sessionValue = msg._session || command.admin || null;
const sessionId = msg._session?.id || msg._session || command.admin || null;
const stationid = normalizeStationId(msg.stationid || msg._updateModuleStationId || command.stationid || '');
const moduleid = normalizeModuleId(command.moduleid || command.moduleId || msg._updateModuleId);
const now = Date.now();
const normalizedCommand = {
    ...command,
    stationid,
    moduleid,
    requestId: String(command.requestId || command.firmwareSessionId || command.firmware?.sessionId || command.firmware?.requestId || ('update-module-' + stationid + '-' + moduleid + '-' + now)),
    timerequested: Number(command.timerequested || now)
};

if (!authUser) {
    node.warn('Update module flow requires authenticated dashboard context');
    return [null, null, null];
}

const isAdmin = authUser.role === 'admin' || authUser.username === 'chargerent';
if (!isAdmin && authUser.commands?.updates !== true) {
    return [null, buildResponse(sessionValue, normalizedCommand, 0, 'Permission denied'), null];
}

if (!stationid || !moduleid) {
    return [null, buildResponse(sessionValue, normalizedCommand, 0, 'Missing stationid or moduleid'), null];
}

const kiosk = msg.kioskDoc || null;
if (!kiosk) {
    return [null, buildResponse(sessionValue, normalizedCommand, 0, 'Kiosk ' + stationid + ' not found'), null];
}

const hardwareType = String(kiosk?.hardware?.type || '').toUpperCase();
const isV2 = kiosk?.isNewSchema === true || V2_TYPES.has(hardwareType);
if (!isV2) {
    return [null, buildResponse(sessionValue, normalizedCommand, 0, stationid + ' is not a V2 kiosk'), null];
}

const modules = Array.isArray(kiosk?.modules) ? kiosk.modules : [];
const targetModule = modules.find((module) => modulesMatch(module?.id, moduleid));
if (!targetModule) {
    return [null, buildResponse(sessionValue, normalizedCommand, 0, 'Module ' + moduleid + ' is not bound to ' + stationid), null];
}

const lastUpdated = parseTimestamp(targetModule?.lastUpdated || kiosk?.lastUpdated || kiosk?.timestamp);
if (!lastUpdated || (now - lastUpdated.getTime()) > ONLINE_WINDOW_MS) {
    return [null, buildResponse(sessionValue, normalizedCommand, 0, 'Module ' + targetModule.id + ' is offline'), null];
}

const publishMessage = {
    topic: '/' + stationid + '/' + targetModule.id + '/user/get',
    payload: JSON.stringify({
        cmd: 'push_version_publish',
        data: ''
    }),
    qos: '1',
    retain: false
};

const firmware = normalizedCommand.firmware && typeof normalizedCommand.firmware === 'object'
    ? normalizedCommand.firmware
    : {};
const firmwareRequestId = String(normalizedCommand.firmwareSessionId || firmware.sessionId || firmware.requestId || normalizedCommand.requestId || '').trim();
let firmwareStatusMessage = null;

if (firmwareRequestId) {
    const firmwareSession = {
        active: true,
        requestId: firmwareRequestId,
        stationid,
        stationId: stationid,
        moduleid: targetModule.id,
        moduleId: targetModule.id,
        target: normalizeFirmwareTarget(firmware.target),
        fileName: String(firmware.fileName || '').trim(),
        version: String(firmware.version || '').trim(),
        size: Number(firmware.size || 0),
        releaseId: String(firmware.release?.id || firmware.releaseId || '').trim(),
        status: 'command_sent',
        phase: 'command_sent',
        statusLabel: 'Update command sent to ' + targetModule.id,
        commandTopic: publishMessage.topic,
        commandPayload: publishMessage.payload,
        bytesDownloaded: 0,
        percent: 0,
        downloadComplete: false,
        installConfirmed: false,
        updatedAtMillis: now,
        commandSentAt: new Date(now).toISOString()
    };

    global.set('activeFirmwareUpdateSession', firmwareSession);
    global.set('firmwareUpdateSession:' + stationid + ':' + targetModule.id, firmwareSession);
    global.set('firmwareUpdateSessionByRequestId:' + firmwareRequestId, firmwareSession);
    firmwareStatusMessage = firmwareSessionWrite(firmwareSession);
}

const responseMessage = buildResponse(
    sessionValue,
    { ...normalizedCommand, moduleid: targetModule.id, requestId: firmwareRequestId || normalizedCommand.requestId },
    1,
    'Module update requested for ' + targetModule.id
);

node.warn('Dashboard requested module update ' + normalizedCommand.requestId + ' for ' + stationid + '/' + targetModule.id + ' on user/get (session ' + (sessionId || 'n/a') + ', firmware session ' + (firmwareRequestId || 'n/a') + ')');

return [publishMessage, responseMessage, firmwareStatusMessage];
